  "Jjq3oPYbI26zjxME": "let location = this.item.system.location.key;\n\nif (location)\n{\n    let dropped = this.item.system.weaponsAtLocation;\n\n    if (dropped.length)\n    {\n        this.script.notification(`¡Dejado caer ${dropped.map(i => i.name).join(\", \")}!`)\n        for(let weapon of dropped)\n        {\n            await weapon.system.toggleEquip();\n        }\n    }\n}\n\nlet roll = await new Roll(\"1d10\").roll({allowInteractive : false})\n\nroll.toMessage(this.script.getChatData({flavor : `${this.effect.name} (Duración)`}));\n\nthis.effect.updateSource({\"duration.rounds\" : roll.total})",
  "sx7Ikn8WW00gBFb4": "let location = (Math.ceil(CONFIG.Dice.randomUniform() * 2) == 2 ? \"r\" : \"l\") + \"Arm\"\n\nif (location == \"lArm\")\n{\n\tthis.script.notification(\"Sacado izquierdo\")\n}\nelse if (location == \"rArm\")\n{\n\tthis.script.notification(\"Sacado derecho\")\n}\n\nthis.effect.updateSource({\"flags.wfrp4e.location\" : location});\n\nif (location)\n{\n    let dropped = this.actor.itemTypes.weapon.filter(i => i.isEquipped & i.system.usesHands.includes(location));\n\n    if (dropped.length)\n    {\n        this.script.notification(`¡Dejado caer ${dropped.map(i => i.name).join(\", \")}!`)\n        for(let weapon of dropped)\n        {\n            await weapon.system.toggleEquip();\n        }\n    }\n}\n\nlet roll = await new Roll(\"1d10\").roll({allowInteractive : false})\n\nroll.toMessage(this.script.getChatData({flavor : `${this.effect.name} (Duración)`}));\n\nthis.effect.updateSource({\"duration.rounds\" : roll.total})",
