  "S3Dev4hleOYqDNe9": "if (args.test.options.healWounds) {\n if (args.test.succeeded) \n {\n   let wounds = this.actor.characteristics.int.bonus + Number(args.test.result.SL)\n   if (args.test.options.fieldDressing && args.test.result.reversed)\n   {\n      wounds = this.actor.characteristics.int.bonus + Math.min(1, Number(args.test.result.SL))\n   }\n\targs.test.result.woundsHealed = wounds\n\targs.test.result.other.push(`<b>${this.actor.name}</b> sana <b>${wounds}</b> heridas de su paciente.`)\n   }\n   else if (this.actor.characteristics.int.bonus + Number(args.test.result.SL) < 0)\n   {\n      args.test.result.other.push(`Tu paciente contrae una @UUID[Compendium.wfrp4e-core.items.Item.1hQuVFZt9QnnbWzg]{Infección leve}.`)\n   }\n}",
  "qAEZgtu5CrfUkxhx": "if (args.test.options.staunchBleeding) \n{\n if (args.test.succeeded) \n {\n   let staunch =  Number(args.test.result.SL) + 1\n   if (args.test.options.fieldDressing && args.test.result.reversed)\n   {\n     staunch =  Math.min(1, Number(args.test.result.SL)) + 1\n   }\n   args.test.result.other.push(`<b>${this.actor.name}</b> elimina <b>${staunch}</b> estados de Sangrando de su paciente.`)\n }\n   else if (this.actor.characteristics.int.bonus + Number(args.test.result.SL) < 0)\n   {\n      args.test.result.other.push(`Tu paciente contrae una @UUID[Compendium.wfrp4e-core.items.Item.1hQuVFZt9QnnbWzg]{Infección leve}.`)\n   }\n}",
