  "toSrgcvWq9b5eN0K": "let location = await game.wfrp4e.tables.rollTable(\"hitloc\", {hideDSN: true})\n\nthis.item.updateSource({name : `${this.item.name} (${location.description})`})\nthis.script.message(`<strong>Ubicación:</strong> ${location.description}`, { whisper: ChatMessage.getWhisperRecipients(\"GM\") })",
  "6hAgggYpNR3r4QWC": "let item = await fromUuid(\"Compendium.wfrp4e-core.items.Q2MCUrG2HppMcvN0\")\nitem = item.toObject()\nlet species = args.actor.Species || \"de tu especie\"\nitem.name = `Animosidad (todos los no ${species}s)`\nthis.actor.createEmbeddedDocuments(\"Item\", [item], {fromEffect : this.effect.id})",
