  "KICZPwLvbUSxbDrE": "let table = game.wfrp4e.tables.findTable(\"mutatemental\");\nif (!table)\n{\n\tui.notifications.error(\"No se pudo encontrar una tabla con la clave: mutatemental\")\n}\nlet result = (await table.roll()).results[0];\nlet uuid = `Compendium.${result.documentCollection}.${result.documentId}`\nlet item = await fromUuid(uuid);\n\nif (item)\n{\n    this.script.notification(`Añadido ${item.name}`)\n    this.actor.createEmbeddedDocuments(\"Item\", [item])\n}\nelse \n{\n    ui.notifications.error(\"No se pudo encontrar el Objeto: \" + uuid)\n}",
  "0R0QAr3D024kWPfo": "let table = game.wfrp4e.tables.findTable(\"mutatephys\");\nif (!table)\n{\n\treturn ui.notifications.error(\"No se encontró la tabla de mutación, por favor asegúrate de que una tabla con la clave `mutatephys` ha sido importada al mundo)\n}\nlet result = (await table.roll()).results[0];\nlet uuid = `Compendium.${result.documentCollection}.${result.documentId}`\nlet item = await fromUuid(uuid);\n\nif (item)\n{\n    this.script.notification(`Añadido ${item.name}`)\n    this.actor.createEmbeddedDocuments(\"Item\", [item])\n}\nelse \n{\n    ui.notifications.error(\"No se pudo encontrar el Objeto: \" + uuid)\n}",
  "ft0LaRWZT5WtnptP": "let advantage = this.actor.system.status.advantage.value;\nif (advantage > 0)\n{\n    await this.actor.setAdvantage(0);\n    this.script.notification(\"Ventaja sustraída\")\n}\nelse \n{\n    return this.script.notification(\"¡No hay suficiente Ventaja!\", \"error\")\n}\n\nlet test = await this.actor.setupTrait(this.item, {fields : {slBonus : advantage}})\nawait test.roll();",
  "OGX4BneaYAnV25TO": "let chatData = { whisper: ChatMessage.getWhisperRecipients(\"GM\") }\nlet message = \"\"\n\nlet wounds = foundry.utils.duplicate(this.actor.status.wounds)\nlet regenRoll = await new Roll(\"1d10\").roll({allowInteractive : false});\nlet regen = regenRoll.total;\n\nif (wounds.value >= wounds.max)\n    return\n\nif (wounds.value > 0) \n{\n    wounds.value += regen\n    if (wounds.value > wounds.max)\n    {\n        wounds.value = wounds.max\n    }\n    message += `<b>${this.actor.name}</b> recupera ${regen} Heridas.`\n\n    if (regen == 10)\n    {\n        message += `<br>Adicionalmente, regenera una Herida Crítica.`\n    }\n}\nelse if (regen >= 8) \n{\n    message += `<b>${this.actor.name}</b> sacó un ${regen} y recupera 1 Herida.`\n    wounds.value += 1\n    if (regen == 10)\n    {\n        message += `<br>Adicionalmente, regenera una Herida Crítica.`\n    }\n}\nelse \n{\n    message += `<b>${this.actor.name}</b> Tirada de Regenerar de ${regen} - Sin efecto.`\n}\n\nawait this.actor.update({ \"system.status.wounds\": wounds })\nthis.script.message(message, { whisper: ChatMessage.getWhisperRecipients(\"GM\") })",
  "PmELrzD3RmF9qKkO": "if (this.item.system.specification.value == \"Tamaño\")\n{\n    let size = this.item.specifier;\n    if (!size)\n    {\n        let choice = await ItemDialog.create(ItemDialog.objectToArray(game.wfrp4e.config.actorSizes, this.item.img), 1, \"Escoge Tamaño\");\n        if (choice[0])\n        {\n            size = choice[0]?.name;\n        }\n    }    this.item.updateSource({\"system.specification.value\" : size, name : this.item.baseName})\n    this.effect.updateSource({name : this.effect.name + ` (${size})`})\n}",
