  "sB4KB9bT3nQhAoqG": "// This script needs to be separate because equipTransfer is off on the other effect, and thus won't execute when added to an actor\n\nlet mainEffect = this.item.effects.contents[0];\nif (mainEffect.name.includes(\"<Saber>\"))\n{\n    let choice = await ItemDialog.create(ItemDialog.objectToArray(game.wfrp4e.config.magicLores, this.item.img).sort(WFRP_Utility.nameSorter), 1, \"Escoge Saber\");\n    if (choice.length)\n    {\n        mainEffect.update({name : mainEffect.name.replace(\"<Saber>\", choice[0].name)})\n        this.item.update({name : this.item.name += ` (${choice[0].name})`})\n    }\n}\n\nthis.effect.delete();",
