  "NTFpkiGyBpOtrV0s": "if (this.actor.uuid == this.effect.sourceActor.uuid)\n{\n\treturn;\n}\n\nif (this.actor.has(\"De sangre fría\") && !this.actor.hasSystemEffect(\"nausea\")) { \n  let test = await this.actor.setupSkill(game.i18n.localize(\"NAME.Endurance\"), {appendTitle : `- ${this.effect.name}`})\nawait test.roll();\nif (test.failed)\n{\n\n  let myRoll = await new Roll(\"1d10\").roll({allowInteractive : false});\n  let duration = myRoll.total\n  this.actor.addSystemEffect(\"nausea\");\n  this.script.scriptMessage(`Añadido síntoma Náuseas, duración : ${duration} horas`);\n}\n}\nreturn false;",
